def resolve_log_level(flag, env, default='INFO'):
    if flag:
        return flag
    if env:
        return env
    return default

print('solo env', resolve_log_level(None, 'DEBUG'))
print('flag gana', resolve_log_level('ERROR', 'DEBUG'))
print('default', resolve_log_level(None, None))

