def validate_config(cfg):
    if not cfg.get('input_path') and cfg.get('cmd') == 'ingest':
        raise SystemExit('abort config: falta input_path para ingest')
    return True

print('normalize', 'ok' if validate_config({'cmd': 'normalize'}) else 'no')
try:
    validate_config({'cmd': 'ingest'})
except SystemExit as e:
    print(e)
print('ingest', 'ok' if validate_config({'cmd': 'ingest', 'input_path': 'x.csv'}) else 'no')
